"use client";

import {
  useCallback,
  useId,
  useImperativeHandle,
  useState,
  type KeyboardEvent,
  type Ref,
} from "react";
import { Popover, PopoverContent, PopoverTrigger } from "@/components/ui/popover";
import {
  Command,
  CommandEmpty,
  CommandInput,
  CommandList,
} from "@/components/ui/command";
import type {
  EntityLike,
  EntityPickerHandle,
  EntityPickerProps,
  KindMeta,
  MultiPickerProps,
  PickerMode,
  SinglePickerProps,
} from "./types";
import { defaultMatch } from "./lib/default-match";
import {
  multiSelectionEqual,
  singleSelectionEqual,
} from "./lib/selection-equality";
import { useItemsById } from "./hooks/use-items-by-id";
import { useOpenState } from "./hooks/use-open-state";
import { TriggerButton } from "./parts/trigger-button";
import { ResultRow } from "./parts/result-row";
import { DefaultEmptyState } from "./parts/default-empty-state";

function EntityPickerImpl<T extends EntityLike>(props: EntityPickerProps<T>) {
  const {
    items,
    match,
    placeholder = "Search…",
    open: controlledOpen,
    onOpenChange,
    kinds,
    showKindBadges: showKindBadgesProp,
    renderItem,
    renderTrigger,
    renderEmpty,
    disabled = false,
    triggerLabel,
    id,
    className,
    ref,
  } = props;

  const mode: PickerMode = props.mode === "multi" ? "multi" : "single";
  const value = props.value as T | T[] | null;

  const reactId = useId();
  const listboxId = `${reactId}-listbox`;

  const { open, setOpen: rawSetOpen } = useOpenState({
    controlled: controlledOpen,
    onOpenChange,
  });

  const [query, setQuery] = useState("");

  const setOpen = useCallback(
    (next: boolean) => {
      if (!next) setQuery("");
      rawSetOpen(next);
    },
    [rawSetOpen],
  );

  const itemsById = useItemsById(items);

  const showKindBadges =
    showKindBadgesProp !== undefined
      ? showKindBadgesProp
      : items.some((i) => !!i.kind);

  // Track the trigger element via state (not a ref) so the setter is React's
  // own setState — passes the React Compiler-aware lint rule that flags
  // ref-accessor functions passed to user-rendered functions during render.
  // The ref-fn is stable across renders (React guarantees setState identity).
  const [triggerNode, setTriggerNode] = useState<HTMLElement | null>(null);

  const handleSelect = useCallback(
    (item: T) => {
      if (mode === "multi") {
        const multiProps = props as MultiPickerProps<T>;
        const current = multiProps.value;
        const isSelected = current.some((v) => v.id === item.id);
        const next = isSelected
          ? current.filter((v) => v.id !== item.id)
          : [...current, item];
        if (!multiSelectionEqual(current, next)) {
          multiProps.onChange(next);
        }
      } else {
        const singleProps = props as SinglePickerProps<T>;
        const current = singleProps.value;
        const next = item;
        if (!singleSelectionEqual(current, next)) {
          singleProps.onChange(next);
        }
        setOpen(false);
      }
    },
    [mode, props, setOpen],
  );

  const handleRemoveChip = useCallback(
    (idToRemove: string) => {
      if (mode !== "multi") return;
      const multiProps = props as MultiPickerProps<T>;
      const next = multiProps.value.filter((v) => v.id !== idToRemove);
      if (!multiSelectionEqual(multiProps.value, next)) {
        multiProps.onChange(next);
      }
    },
    [mode, props],
  );

  const handleClear = useCallback(() => {
    if (mode === "multi") {
      const multiProps = props as MultiPickerProps<T>;
      if (multiProps.value.length > 0) multiProps.onChange([]);
    } else {
      const singleProps = props as SinglePickerProps<T>;
      if (singleProps.value !== null) singleProps.onChange(null);
    }
  }, [mode, props]);

  const focusTrigger = useCallback(() => {
    if (!triggerNode) return;
    triggerNode.focus();
  }, [triggerNode]);

  useImperativeHandle(
    ref as Ref<EntityPickerHandle>,
    (): EntityPickerHandle => ({
      focus: focusTrigger,
      open: () => setOpen(true),
      close: () => setOpen(false),
      clear: handleClear,
    }),
    [focusTrigger, setOpen, handleClear],
  );

  const handleTriggerKeyDown = useCallback(
    (e: KeyboardEvent<HTMLDivElement>) => {
      if (disabled) return;
      if (e.key === "Enter" || e.key === " ") {
        e.preventDefault();
        setOpen(true);
        return;
      }
      if (e.key === "ArrowDown") {
        e.preventDefault();
        setOpen(true);
      }
    },
    [disabled, setOpen],
  );

  const handleSearchKeyDown = useCallback(
    (e: KeyboardEvent<HTMLInputElement>) => {
      if (
        e.key === "Backspace" &&
        query.length === 0 &&
        mode === "multi"
      ) {
        const multiProps = props as MultiPickerProps<T>;
        if (multiProps.value.length > 0) {
          e.preventDefault();
          const last = multiProps.value[multiProps.value.length - 1];
          handleRemoveChip(last.id);
        }
      }
    },
    [query, mode, props, handleRemoveChip],
  );

  const filterFn = useCallback(
    (entityId: string, search: string): number => {
      const item = itemsById.get(entityId);
      if (!item) return 0;
      try {
        const result = match
          ? match(item, search)
          : defaultMatch(item, search);
        return result ? 1 : 0;
      } catch (err) {
        if (process.env.NODE_ENV !== "production") {
          console.error(
            `[entity-picker] match threw for item "${item.id}":`,
            err,
          );
        }
        return 0;
      }
    },
    [itemsById, match],
  );

  const renderTriggerNode = renderTrigger ? (
    renderTrigger({
      value,
      open,
      triggerRef: setTriggerNode,
    })
  ) : (
    <TriggerButton<T>
      ref={setTriggerNode}
      id={id}
      mode={mode}
      value={value}
      open={open}
      disabled={disabled}
      triggerLabel={triggerLabel}
      kinds={kinds}
      showKindBadges={showKindBadges}
      listboxId={listboxId}
      className={className}
      onClick={() => setOpen(!open)}
      onKeyDown={handleTriggerKeyDown}
      onRemoveChip={handleRemoveChip}
    />
  );

  const valueMap = (() => {
    const out = new Set<string>();
    if (mode === "multi") {
      const m = props as MultiPickerProps<T>;
      for (const v of m.value) out.add(v.id);
    } else {
      const s = props as SinglePickerProps<T>;
      if (s.value) out.add(s.value.id);
    }
    return out;
  })();

  return (
    <Popover open={open} onOpenChange={setOpen}>
      <PopoverTrigger asChild>{renderTriggerNode}</PopoverTrigger>
      <PopoverContent
        align="start"
        sideOffset={4}
        className="w-(--radix-popover-trigger-width) min-w-60 p-0"
      >
        <Command filter={filterFn} loop>
          <CommandInput
            placeholder={placeholder}
            value={query}
            onValueChange={setQuery}
            onKeyDown={handleSearchKeyDown}
            aria-label={triggerLabel ?? "Search entities"}
          />
          <CommandList id={listboxId} aria-multiselectable={mode === "multi"}>
            <CommandEmpty>
              {renderEmpty ? (
                renderEmpty({ query, itemCount: items.length })
              ) : (
                <DefaultEmptyState query={query} itemCount={items.length} />
              )}
            </CommandEmpty>
            {items.map((item) => {
              const selected = valueMap.has(item.id);
              const kindMeta: KindMeta | undefined =
                item.kind && kinds ? kinds[item.kind] : undefined;
              const customNode = renderItem
                ? renderItem(item, { selected, query })
                : undefined;
              return (
                <ResultRow<T>
                  key={item.id}
                  item={item}
                  selected={selected}
                  kindMeta={kindMeta}
                  showKindBadges={showKindBadges}
                  onSelect={() => handleSelect(item)}
                  customRender={customNode}
                />
              );
            })}
          </CommandList>
        </Command>
      </PopoverContent>
    </Popover>
  );
}

export function EntityPicker<T extends EntityLike>(
  props: SinglePickerProps<T>,
): React.JSX.Element;
export function EntityPicker<T extends EntityLike>(
  props: MultiPickerProps<T>,
): React.JSX.Element;
export function EntityPicker<T extends EntityLike>(
  props: EntityPickerProps<T>,
): React.JSX.Element {
  return EntityPickerImpl(props);
}

export { EntityPicker } from "./entity-picker";
export type {
  CommonPickerProps,
  EntityLike,
  EntityPickerHandle,
  EntityPickerProps,
  KindMeta,
  MultiPickerProps,
  PickerMode,
  RenderEmptyContext,
  RenderItemContext,
  RenderTriggerContext,
  SinglePickerProps,
} from "./types";
export { meta } from "./meta";

import type { ReactNode, Ref } from "react";

export interface EntityLike {
  id: string;
  label: string;
  kind?: string;
}

export interface KindMeta {
  label: string;
  color?: string;
}

export type PickerMode = "single" | "multi";

export interface RenderItemContext {
  selected: boolean;
  query: string;
}

export interface RenderTriggerContext<T extends EntityLike> {
  value: T | T[] | null;
  open: boolean;
  triggerRef: (node: HTMLElement | null) => void;
}

export interface RenderEmptyContext {
  query: string;
  itemCount: number;
}

export interface CommonPickerProps<T extends EntityLike> {
  items: ReadonlyArray<T>;

  match?: (item: T, query: string) => boolean;
  placeholder?: string;

  open?: boolean;
  onOpenChange?: (open: boolean) => void;

  kinds?: Record<string, KindMeta>;
  showKindBadges?: boolean;

  renderItem?: (item: T, ctx: RenderItemContext) => ReactNode;
  renderTrigger?: (ctx: RenderTriggerContext<T>) => ReactNode;
  renderEmpty?: (ctx: RenderEmptyContext) => ReactNode;

  disabled?: boolean;
  triggerLabel?: string;
  id?: string;
  className?: string;

  ref?: Ref<EntityPickerHandle>;
}

export interface SinglePickerProps<T extends EntityLike>
  extends CommonPickerProps<T> {
  mode?: "single";
  value: T | null;
  onChange: (value: T | null) => void;
}

export interface MultiPickerProps<T extends EntityLike>
  extends CommonPickerProps<T> {
  mode: "multi";
  value: T[];
  onChange: (value: T[]) => void;
}

export type EntityPickerProps<T extends EntityLike> =
  | SinglePickerProps<T>
  | MultiPickerProps<T>;

export interface EntityPickerHandle {
  focus(): void;
  open(): void;
  close(): void;
  clear(): void;
}

"use client";

import { useEffect, useMemo, useRef } from "react";
import type { EntityLike } from "../types";

export function useItemsById<T extends EntityLike>(
  items: ReadonlyArray<T>,
): Map<string, T> {
  const map = useMemo(() => {
    const out = new Map<string, T>();
    for (const item of items) {
      if (out.has(item.id)) {
        if (process.env.NODE_ENV !== "production") {
          console.error(
            `[entity-picker] duplicate id "${item.id}" in items; later occurrences are ignored.`,
          );
        }
        continue;
      }
      out.set(item.id, item);
    }
    return out;
  }, [items]);

  const stabilityRef = useRef({ last: items, count: 0, warned: false });
  useEffect(() => {
    const tracker = stabilityRef.current;
    if (tracker.last === items) {
      tracker.count = 0;
      return;
    }
    tracker.last = items;
    tracker.count++;
    if (
      tracker.count > 5 &&
      !tracker.warned &&
      process.env.NODE_ENV !== "production"
    ) {
      tracker.warned = true;
      console.warn(
        "[entity-picker] `items` prop is changing every render. " +
          "Wrap with `useMemo` or hoist to module scope to avoid re-derivation.",
      );
    }
  }, [items]);

  return map;
}

"use client";

import { useCallback, useEffect, useRef, useState } from "react";

interface UseOpenStateArgs {
  controlled: boolean | undefined;
  onOpenChange: ((open: boolean) => void) | undefined;
}

interface UseOpenStateResult {
  open: boolean;
  setOpen: (next: boolean) => void;
}

export function useOpenState({
  controlled,
  onOpenChange,
}: UseOpenStateArgs): UseOpenStateResult {
  const isControlled = controlled !== undefined;
  const [internalOpen, setInternalOpen] = useState(false);

  const onOpenChangeRef = useRef(onOpenChange);
  useEffect(() => {
    onOpenChangeRef.current = onOpenChange;
  });

  const setOpen = useCallback(
    (next: boolean) => {
      if (!isControlled) setInternalOpen(next);
      onOpenChangeRef.current?.(next);
    },
    [isControlled],
  );

  const open = isControlled ? (controlled as boolean) : internalOpen;
  return { open, setOpen };
}

import type { EntityLike } from "../types";

export function defaultMatch<T extends EntityLike>(
  item: T,
  query: string,
): boolean {
  if (query.length === 0) return true;
  return item.label.toLowerCase().includes(query.toLowerCase());
}

import type { EntityLike } from "../types";

export function valueToArray<T extends EntityLike>(
  value: T | T[] | null,
): T[] {
  if (value === null || value === undefined) return [];
  if (Array.isArray(value)) return value;
  return [value];
}

export function valueIds<T extends EntityLike>(
  value: T | T[] | null,
): Set<string> {
  const out = new Set<string>();
  for (const item of valueToArray(value)) out.add(item.id);
  return out;
}

export function hasId<T extends EntityLike>(
  value: T | T[] | null,
  id: string,
): boolean {
  if (value === null || value === undefined) return false;
  if (Array.isArray(value)) return value.some((v) => v.id === id);
  return value.id === id;
}

import type { EntityLike } from "../types";

export function singleSelectionEqual<T extends EntityLike>(
  a: T | null,
  b: T | null,
): boolean {
  if (a === null && b === null) return true;
  if (a === null || b === null) return false;
  return a.id === b.id;
}

export function multiSelectionEqual<T extends EntityLike>(
  a: ReadonlyArray<T>,
  b: ReadonlyArray<T>,
): boolean {
  if (a.length !== b.length) return false;
  if (a.length === 0) return true;
  const seen = new Set<string>();
  for (const item of a) seen.add(item.id);
  for (const item of b) {
    if (!seen.has(item.id)) return false;
  }
  return true;
}

"use client";

import type { EntityLike, KindMeta } from "../types";
import { Chip } from "./chip";

interface ChipClusterProps<T extends EntityLike> {
  value: T[];
  kinds: Record<string, KindMeta> | undefined;
  showKindBadges: boolean;
  onRemove: (id: string) => void;
  disabled?: boolean;
}

export function ChipCluster<T extends EntityLike>({
  value,
  kinds,
  showKindBadges,
  onRemove,
  disabled,
}: ChipClusterProps<T>) {
  if (value.length === 0) return null;
  return (
    <div className="flex flex-1 flex-wrap items-center gap-1">
      {value.map((entity) => (
        <Chip
          key={entity.id}
          entity={entity}
          kindMeta={entity.kind ? kinds?.[entity.kind] : undefined}
          showKind={showKindBadges}
          onRemove={() => onRemove(entity.id)}
          disabled={disabled}
        />
      ))}
    </div>
  );
}

"use client";

import { X } from "lucide-react";
import { Badge } from "@/components/ui/badge";
import { cn } from "@/lib/utils";
import type { EntityLike, KindMeta } from "../types";

interface ChipProps<T extends EntityLike> {
  entity: T;
  kindMeta: KindMeta | undefined;
  showKind: boolean;
  onRemove: () => void;
  disabled?: boolean;
}

export function Chip<T extends EntityLike>({
  entity,
  kindMeta,
  showKind,
  onRemove,
  disabled,
}: ChipProps<T>) {
  return (
    <Badge
      variant="secondary"
      className="gap-1 pr-0.5 text-xs"
    >
      {showKind && entity.kind ? (
        <span
          className={cn(
            "font-mono text-[10px] uppercase opacity-70",
            kindMeta?.color ? "text-[var(--kind-color)]" : undefined,
          )}
          style={
            kindMeta?.color
              ? ({ "--kind-color": kindMeta.color } as React.CSSProperties)
              : undefined
          }
        >
          {kindMeta?.label ?? entity.kind}
        </span>
      ) : null}
      <span className="truncate">{entity.label}</span>
      <button
        type="button"
        aria-label={`Remove ${entity.label}`}
        disabled={disabled}
        onClick={(e) => {
          e.stopPropagation();
          onRemove();
        }}
        onKeyDown={(e) => {
          // Stop Enter/Space from bubbling to the parent trigger which would toggle the popover.
          if (e.key === "Enter" || e.key === " ") e.stopPropagation();
        }}
        className="ml-0.5 rounded-sm p-0.5 hover:bg-foreground/10 disabled:opacity-50"
      >
        <X aria-hidden="true" className="size-3" />
      </button>
    </Badge>
  );
}

interface DefaultEmptyStateProps {
  query: string;
  itemCount: number;
}

export function DefaultEmptyState({
  itemCount,
}: DefaultEmptyStateProps) {
  if (itemCount === 0) {
    return (
      <p role="status" className="px-2 text-center text-xs text-muted-foreground">
        Nothing to pick from
      </p>
    );
  }
  return (
    <p role="status" className="px-2 text-center text-xs text-muted-foreground">
      No results
    </p>
  );
}

"use client";

import { Badge } from "@/components/ui/badge";
import { cn } from "@/lib/utils";
import type { KindMeta } from "../types";

interface KindBadgeProps {
  kindKey: string;
  meta: KindMeta | undefined;
  className?: string;
}

export function KindBadge({ kindKey, meta, className }: KindBadgeProps) {
  const display = meta?.label ?? kindKey;
  const style = meta?.color
    ? ({ "--kind-color": meta.color } as React.CSSProperties)
    : undefined;
  return (
    <Badge
      variant="secondary"
      className={cn(
        "font-mono text-[10px] uppercase tracking-[0.12em]",
        meta?.color
          ? "bg-[var(--kind-color)]/15 text-[var(--kind-color)]"
          : "text-muted-foreground",
        className,
      )}
      style={style}
    >
      {display}
    </Badge>
  );
}

"use client";

import type { ReactNode } from "react";
import { CommandItem } from "@/components/ui/command";
import type { EntityLike, KindMeta } from "../types";
import { KindBadge } from "./kind-badge";

interface ResultRowProps<T extends EntityLike> {
  item: T;
  selected: boolean;
  kindMeta: KindMeta | undefined;
  showKindBadges: boolean;
  onSelect: () => void;
  customRender?: ReactNode;
}

export function ResultRow<T extends EntityLike>({
  item,
  selected,
  kindMeta,
  showKindBadges,
  onSelect,
  customRender,
}: ResultRowProps<T>) {
  return (
    <CommandItem
      value={item.id}
      onSelect={onSelect}
      data-checked={selected ? "true" : undefined}
      aria-selected={selected || undefined}
      className="flex items-center gap-2"
    >
      {customRender ?? (
        <>
          {showKindBadges && item.kind ? (
            <KindBadge kindKey={item.kind} meta={kindMeta} />
          ) : null}
          <span className="truncate">{item.label}</span>
        </>
      )}
    </CommandItem>
  );
}

"use client";

import { forwardRef, type KeyboardEventHandler } from "react";
import { ChevronDown } from "lucide-react";
import type { EntityLike, KindMeta, PickerMode } from "../types";
import { ChipCluster } from "./chip-cluster";
import { KindBadge } from "./kind-badge";
import { cn } from "@/lib/utils";

interface TriggerButtonProps<T extends EntityLike> {
  id?: string;
  mode: PickerMode;
  value: T | T[] | null;
  open: boolean;
  disabled?: boolean;
  triggerLabel?: string;
  kinds?: Record<string, KindMeta>;
  showKindBadges: boolean;
  listboxId: string;
  ariaLabelledBy?: string;
  className?: string;
  onClick: () => void;
  onKeyDown: KeyboardEventHandler<HTMLDivElement>;
  onRemoveChip: (id: string) => void;
}

function TriggerButtonInner<T extends EntityLike>(
  props: TriggerButtonProps<T>,
  ref: React.Ref<HTMLDivElement>,
) {
  const {
    id,
    mode,
    value,
    open,
    disabled,
    triggerLabel,
    kinds,
    showKindBadges,
    listboxId,
    ariaLabelledBy,
    className,
    onClick,
    onKeyDown,
    onRemoveChip,
  } = props;

  const placeholder = triggerLabel ?? "Select…";
  const isMulti = mode === "multi";
  const multiValue = Array.isArray(value) ? value : [];
  const singleValue = !Array.isArray(value) ? value : null;
  const empty = isMulti ? multiValue.length === 0 : singleValue === null;
  const singleKindMeta =
    singleValue?.kind && kinds ? kinds[singleValue.kind] : undefined;

  return (
    <div
      ref={ref}
      id={id}
      role="button"
      tabIndex={disabled ? -1 : 0}
      aria-haspopup="listbox"
      aria-expanded={open}
      aria-controls={listboxId}
      aria-disabled={disabled || undefined}
      aria-label={!ariaLabelledBy ? triggerLabel : undefined}
      aria-labelledby={ariaLabelledBy}
      onClick={() => {
        if (!disabled) onClick();
      }}
      onKeyDown={onKeyDown}
      className={cn(
        "group flex min-h-9 w-full cursor-default items-center gap-1.5 rounded-lg border border-input bg-transparent px-2 py-1 text-sm outline-none transition-colors",
        "focus-visible:border-ring focus-visible:ring-3 focus-visible:ring-ring/50",
        "data-[disabled=true]:cursor-not-allowed data-[disabled=true]:opacity-50",
        "dark:bg-input/30",
        className,
      )}
      data-disabled={disabled || undefined}
      data-state={open ? "open" : "closed"}
    >
      {isMulti ? (
        multiValue.length === 0 ? (
          <span className="flex-1 truncate text-muted-foreground">
            {placeholder}
          </span>
        ) : (
          <ChipCluster
            value={multiValue}
            kinds={kinds}
            showKindBadges={showKindBadges}
            onRemove={onRemoveChip}
            disabled={disabled}
          />
        )
      ) : empty ? (
        <span className="flex-1 truncate text-muted-foreground">
          {placeholder}
        </span>
      ) : (
        <span className="flex flex-1 items-center gap-2 truncate">
          {showKindBadges && singleValue?.kind ? (
            <KindBadge
              kindKey={singleValue.kind}
              meta={singleKindMeta}
            />
          ) : null}
          <span className="truncate text-foreground">
            {singleValue?.label}
          </span>
        </span>
      )}
      <ChevronDown
        aria-hidden="true"
        className="ml-auto size-4 shrink-0 text-muted-foreground transition-transform group-data-[state=open]:rotate-180"
      />
    </div>
  );
}

// React 19's first-class ref-as-prop would also work, but Radix's
// PopoverTrigger asChild-Slot ref composition expects forwardRef-style
// children for legacy reasons in some chains. forwardRef is safe here
// since this component is non-generic over its own DOM type.
export const TriggerButton = forwardRef(TriggerButtonInner) as <
  T extends EntityLike,
>(
  props: TriggerButtonProps<T> & { ref?: React.Ref<HTMLDivElement> },
) => React.ReactElement;
